**Database Schema Design**

We will design a database schema using MySQL, a popular relational database management system. The schema will consist of the following tables:

### Table: `currencies`

```sql
-- currencies.sql

CREATE TABLE currencies (
  id INT PRIMARY KEY AUTO_INCREMENT,
  code VARCHAR(3) NOT NULL,
  name VARCHAR(50) NOT NULL,
  symbol VARCHAR(5) NOT NULL,
  rate DECIMAL(10, 6) NOT NULL
);

-- Example data
INSERT INTO currencies (code, name, symbol, rate)
VALUES
  ('USD', 'US Dollar', '$', 1.000000),
  ('EUR', 'Euro', '€', 0.883621),
  ('GBP', 'British Pound', '£', 0.762419);
```

### Table: `conversion_history`

```sql
-- conversion_history.sql

CREATE TABLE conversion_history (
  id INT PRIMARY KEY AUTO_INCREMENT,
  from_currency_id INT NOT NULL,
  to_currency_id INT NOT NULL,
  amount DECIMAL(10, 6) NOT NULL,
  converted_amount DECIMAL(10, 6) NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (from_currency_id) REFERENCES currencies(id),
  FOREIGN KEY (to_currency_id) REFERENCES currencies(id)
);

-- Example data
INSERT INTO conversion_history (from_currency_id, to_currency_id, amount, converted_amount)
VALUES
  (1, 2, 100.00, 88.3621),
  (2, 3, 100.00, 76.2419);
```

### Table: `users`

```sql
-- users.sql

CREATE TABLE users (
  id INT PRIMARY KEY AUTO_INCREMENT,
  username VARCHAR(50) NOT NULL,
  email VARCHAR(100) NOT NULL,
  password VARCHAR(255) NOT NULL
);

-- Example data
INSERT INTO users (username, email, password)
VALUES
  ('john', 'john@example.com', 'password123'),
  ('jane', 'jane@example.com', 'password123');
```

### Table: `user_conversions`

```sql
-- user_conversions.sql

CREATE TABLE user_conversions (
  id INT PRIMARY KEY AUTO_INCREMENT,
  user_id INT NOT NULL,
  from_currency_id INT NOT NULL,
  to_currency_id INT NOT NULL,
  amount DECIMAL(10, 6) NOT NULL,
  converted_amount DECIMAL(10, 6) NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id),
  FOREIGN KEY (from_currency_id) REFERENCES currencies(id),
  FOREIGN KEY (to_currency_id) REFERENCES currencies(id)
);

-- Example data
INSERT INTO user_conversions (user_id, from_currency_id, to_currency_id, amount, converted_amount)
VALUES
  (1, 1, 2, 100.00, 88.3621),
  (2, 2, 3, 100.00, 76.2419);
```

**Indexes**

To improve query performance, we will create indexes on the following columns:

```sql
-- indexes.sql

CREATE INDEX idx_currencies_code ON currencies (code);
CREATE INDEX idx_conversion_history_from_currency_id ON conversion_history (from_currency_id);
CREATE INDEX idx_conversion_history_to_currency_id ON conversion_history (to_currency_id);
CREATE INDEX idx_user_conversions_user_id ON user_conversions (user_id);
CREATE INDEX idx_user_conversions_from_currency_id ON user_conversions (from_currency_id);
CREATE INDEX idx_user_conversions_to_currency_id ON user_conversions (to_currency_id);
```

**API Endpoints**

We will create the following API endpoints using Node.js and Express.js:

### GET /currencies

```javascript
// currencies.controller.js

const express = require('express');
const router = express.Router();
const db = require('./db');

router.get('/', async (req, res) => {
  const currencies = await db.query('SELECT * FROM currencies');
  res.json(currencies);
});
```

### GET /conversions

```javascript
// conversions.controller.js

const express = require('express');
const router = express.Router();
const db = require('./db');

router.get('/', async (req, res) => {
  const conversions = await db.query('SELECT * FROM conversion_history');
  res.json(conversions);
});
```

### POST /conversions

```javascript
// conversions.controller.js

const express = require('express');
const router = express.Router();
const db = require('./db');

router.post('/', async (req, res) => {
  const { fromCurrencyId, toCurrencyId, amount } = req.body;
  const convertedAmount = await db.query('SELECT rate FROM currencies WHERE id = ?', [fromCurrencyId]);
  const result = await db.query('INSERT INTO conversion_history SET ? ON DUPLICATE KEY UPDATE converted_amount = VALUES(converted_amount)', {
    from_currency_id: fromCurrencyId,
    to_currency_id: toCurrencyId,
    amount,
    converted_amount: amount * convertedAmount[0].rate
  });
  res.json(result);
});
```

### GET /users

```javascript
// users.controller.js

const express = require('express');
const router = express.Router();
const db = require('./db');

router.get('/', async (req, res) => {
  const users = await db.query('SELECT * FROM users');
  res.json(users);
});
```

### POST /users

```javascript
// users.controller.js

const express = require('express');
const router = express.Router();
const db = require('./db);

router.post('/', async (req, res) => {
  const { username, email, password } = req.body;
  const result = await db.query('INSERT INTO users SET ?', { username, email, password });
  res.json(result);
});
```

**Redis Caching**

We will use Redis as a caching layer to store frequently accessed data. We will create a Redis client using the `redis` package:

```javascript
// redis.client.js

const redis = require('redis');
const client = redis.createClient();

client.on('connect', () => {
  console.log('Connected to Redis');
});

client.on('error', (err) => {
  console.error('Error connecting to Redis:', err);
});
```

We will use the Redis client to cache the currencies data:

```javascript
// currencies.controller.js

const express = require('express');
const router = express.Router();
const db = require('./db);
const redisClient = require('./redis.client');

router.get('/', async (req, res) => {
  const cacheKey = 'currencies';
  const cachedData = await redisClient.get(cacheKey);
  if (cachedData) {
    return res.json(JSON.parse(cachedData));
  }
  const currencies = await db.query('SELECT * FROM currencies');
  await redisClient.set(cacheKey, JSON.stringify(currencies));
  res.json(currencies);
});
```

Note that this is a basic example and you should consider implementing authentication and authorization mechanisms to secure your API. Additionally, you should consider using a more robust caching strategy, such as using a cache expiration time and implementing cache invalidation.

