// src/utils/currency.utils.ts
import { CurrencyCode, ConversionResult } from '../types/currency.types';

export const FIXED_RATES: Record<CurrencyCode, Record<CurrencyCode, number>> = {
  EUR: { EUR: 1, USD: 1.08, MAD: 10.8 },
  USD: { EUR: 0.93, USD: 1, MAD: 9.95 },
  MAD: { EUR: 0.093, USD: 0.1, MAD: 1 },
};

export const formatCurrency = (value: number, currency: CurrencyCode): string => {
  return new Intl.NumberFormat('fr-FR', {
    style: 'currency',
    currency,
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
};

export const calculateConversion = (
  amount: number,
  from: CurrencyCode,
  to: CurrencyCode
): ConversionResult => {
  if (amount <= 0) {
    return {
      amount,
      from,
      to,
      result: 0,
      rate: 0,
    };
  }

  const rate = FIXED_RATES[from][to];
  const result = amount * rate;

  return {
    amount,
    from,
    to,
    result,
    rate,
  };
};

code_blocks.useCurrencyConversion.ts:
// src/hooks/useCurrencyConversion.ts
import { useState, useEffect, useCallback } from 'react';
import { CurrencyCode, ConversionResult } from '../types/currency.types';
import { calculateConversion } from '../utils/currency.utils';

export const useCurrencyConversion = () => {
  const [amount, setAmount] = useState<number>(1);
  const [fromCurrency, setFromCurrency] = useState<CurrencyCode>('EUR');
  const [toCurrency, setToCurrency] = useState<CurrencyCode>('USD');
  const [result, setResult] = useState<ConversionResult | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const convertCurrency = useCallback(() => {
    setIsLoading(true);
    setError(null);

    try {
      const conversionResult = calculateConversion(amount, fromCurrency, toCurrency);
      setResult(conversionResult);
    } catch (err) {
      setError('Une erreur est survenue lors de la conversion');
      console.error('Conversion error:', err);
    } finally {
      setIsLoading(false);
    }
  }, [amount, fromCurrency, toCurrency]);

  useEffect(() => {
    convertCurrency();
  }, [convertCurrency]);

  const swapCurrencies = () => {
    setFromCurrency(toCurrency);
    setToCurrency(fromCurrency);
  };

  return {
    amount,
    setAmount,
    fromCurrency,
    setFromCurrency,
    toCurrency,
    setToCurrency,
    result,
    isLoading,
    error,
    swapCurrencies,
    convertCurrency,
  };
};

