import React from 'react';

interface CurrencyInputProps {
  value: number;
  onChange: (value: number) => void;
  currency: string;
  id: string;
  label: string;
  'aria-label': string;
}

export const CurrencyInput: React.FC<CurrencyInputProps> = ({
  value,
  onChange,
  currency,
  id,
  label,
  'aria-label': ariaLabel,
}) => {
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    if (value === '' || /^[0-9]+(\.[0-9]*)?$/.test(value)) {
      onChange(value === '' ? 0 : parseFloat(value));
    }
  };

  return (
    <div className="currency-input">
      <label htmlFor={id} className="currency-input__label">
        {label}
      </label>
      <div className="currency-input__container">
        <input
          id={id}
          type="number"
          value={value <= 0 ? '' : value}
          onChange={handleChange}
          min="0"
          step="0.01"
          className="currency-input__field"
          aria-label={ariaLabel}
        />
        <span className="currency-input__currency">{currency}</span>
      </div>
    </div>
  );
};

