│   │   │   ├── tasks.py      # Task-related endpoints
│   │   └── health.py         # Health check endpoint
│   └── storage.py            # In-memory storage implementation
├── frontend/                 # React + TypeScript frontend
│   ├── public/               # Static files
│   ├── src/
│   │   ├── components/       # Reusable UI components
│   │   │   ├── TaskForm.tsx
