```python backend/api/v1/websocket.py
"""WebSocket endpoint for real-time communication."""
from fastapi import APIRouter, WebSocket, WebSocketDisconnect
from typing import Dict, List
import json
from .....backend.services import room_service, user_service

router = APIRouter()

class ConnectionManager:
    def __init__(self):
        self.active_connections: Dict[str, List[WebSocket]] = {}

    async def connect(self, websocket: WebSocket, room_id: str, user_id: str):
        await websocket.accept()
        if room_id not in self.active_connections:
            self.active_connections[room_id] = []
        self.active_connections[room_id].append(websocket)

        # Notify room of new user
        await self.broadcast_presence(room_id, user_id, "online")

    async def disconnect(self, websocket: WebSocket, room_id: str, user_id: str):
        if room_id in self.active_connections:
            self.active_connections[room_id].remove(websocket)
            if not self.active_connections[room_id]:
                del self.active_connections[room_id]

            # Notify room of user leaving
            await self.broadcast_presence(room_id, user_id, "offline")

    async def broadcast(self, room_id: str, message: str):
        if room_id in self.active_connections:
            for connection in self.active_connections[room_id]:
                await connection.send_text(message)

    async def broadcast_presence(self, room_id: str, user_id: str, status: str):
        presence_message = {
            "type": "presence",
            "user_id": user_id,
            "status": status,
            "timestamp": int(time.time())
        }
        await self.broadcast(room_id, json.dumps(presence_message))

manager = ConnectionManager()

@router.websocket("/ws/{room_id}/{user_id}")
async def websocket_endpoint(
    websocket: WebSocket,
    room_id: str,
    user_id: str
):
    await manager.connect(websocket, room_id, user_id)
    try:
        while True:
            data = await websocket.receive_text()
            message = json.loads(data)

            # Broadcast message to room
            await manager.broadcast(room_id, json.dumps({
                "type": "message",
                "user_id": user_id,
                "content": message["content"],
                "timestamp": int(time.time())
            }))
    except WebSocketDisconnect:
        await manager.disconnect(websocket, room_id, user_id)
