```python backend/services/room_service.py
"""Room business logic."""
from typing import Dict, List, Optional
from ..models.room import Room, RoomCreate, RoomUpdate
import uuid
from datetime import datetime

class RoomService:
    def __init__(self):
        self.rooms: Dict[str, Room] = {}

    def create_room(self, room_data: RoomCreate) -> Room:
        """Create a new room."""
        room_id = str(uuid.uuid4())
        room = Room(
            id=room_id,
            name=room_data.name,
            description=room_data.description,
            created_at=datetime.now(),
            updated_at=datetime.now()
        )
        self.rooms[room_id] = room
        return room

    def get_room(self, room_id: str) -> Optional[Room]:
        """Get a room by ID."""
        return self.rooms.get(room_id)

    def get_all_rooms(self) -> List[Room]:
        """Get all rooms."""
        return list(self.rooms.values())

    def update_room(self, room_id: str, room_update: RoomUpdate) -> Optional[Room]:
        """Update a room."""
        if room_id not in self.rooms:
            return None
        room = self.rooms[room_id]
        if room_update.name:
            room.name = room_update.name
        if room_update.description:
            room.description = room_update.description
        room.updated_at = datetime.now()
        return room

    def delete_room(self, room_id: str) -> bool:
        """Delete a room."""
        if room_id in self.rooms:
            del self.rooms[room_id]
            return True
        return False

room_service = RoomService()
